# ── Logo header ──────────────────────────────────────────────────────────────
st.markdown(f'''
<div class="header-container">
    <img src="data:image/png;base64,{LOGO_B64}" alt="Golf Los Andes"/>
</div>
''', unsafe_allow_html=True)

# ── Datos ────────────────────────────────────────────────────────────────────
@st.cache_data
def cargar_datos():
    with open("propietarios.json", "r", encoding="utf-8") as f:
        return pd.DataFrame(json.load(f))

if "df" not in st.session_state:
    st.session_state.df = cargar_datos()

df = st.session_state.df

# ── Sidebar ──────────────────────────────────────────────────────────────────
with st.sidebar:
    st.markdown("## 📋 Menú")
    st.markdown("---")
    pagina = st.radio("", [
        "🔍 Buscar Propietario",
        "📊 Datos Propietarios",
        "💰 Operaciones",
        "📈 Dashboard"
    ], label_visibility="collapsed")
    st.markdown("---")
    st.markdown(f"**Total:** {len(df)} propietarios")
    st.markdown(f"**Torres:** 1 al 19")

# ══════════════════════════════════════════════════════════════════════════════
# PÁGINA: BUSCAR PROPIETARIO
# ══════════════════════════════════════════════════════════════════════════════
if pagina == "🔍 Buscar Propietario":

    st.markdown("### 🔍 Buscar Cliente")

    # Stats
    c1,c2,c3,c4 = st.columns(4)
    c1.metric("Total Propietarios", len(df))
    c2.metric("Con Torre/Dpto", df[df["torre"].str.strip()!=""].shape[0])
    c3.metric("En Alquiler", df[df["situacion"].str.lower().str.contains("alquil",na=False)].shape[0])
    c4.metric("Sin DNI", df[df["dni"]==""].shape[0])

    st.markdown("---")

    # Campos de búsqueda
    col_dni, col_cod, col_nom = st.columns([2, 2, 3])
    with col_dni:
        buscar_dni = st.text_input("**DNI:**", placeholder="Ej: 08165632", key="inp_dni")
    with col_cod:
        buscar_cod = st.text_input("**Código** (Torre+Dpto):", placeholder="Ej: 01101", key="inp_cod",
            help="Torre 01 + Dpto 101 = 01101")
    with col_nom:
        buscar_nom = st.text_input("**Nombres:**", placeholder="Ingrese nombre...", key="inp_nom")

    # Botones
    b1,b2,b3,b4 = st.columns(4)
    with b1: btn_buscar  = st.button("🔍 BUSCAR")
    with b2: btn_agregar = st.button("➕ AGREGAR")
    with b3: btn_limpiar = st.button("🗑️ LIMPIAR")
    with b4: btn_eliminar= st.button("❌ ELIMINAR")

    # ── LIMPIAR ──
    if btn_limpiar:
        st.session_state.inp_dni = ""
        st.session_state.inp_cod = ""
        st.session_state.inp_nom = ""
        st.rerun()

    # ── BUSCAR ──
    resultado = df.copy()
    if buscar_dni:
        resultado = resultado[resultado["dni"].str.contains(buscar_dni.strip(), na=False)]
    if buscar_cod:
        resultado = resultado[resultado["codigo"].str.contains(buscar_cod.strip(), na=False)]
    if buscar_nom:
        resultado = resultado[resultado["nombre"].str.upper().str.contains(buscar_nom.upper(), na=False)]

    hay_busqueda = buscar_dni or buscar_cod or buscar_nom or btn_buscar

    # ── AGREGAR ──
    if btn_agregar:
        st.session_state["modo_agregar"] = True

    if st.session_state.get("modo_agregar"):
        st.markdown("---")
        st.markdown("#### ➕ Agregar Nuevo Propietario")
        with st.form("form_agregar"):
            fa1, fa2, fa3 = st.columns(3)
            with fa1:
                n_torre = st.text_input("Torre", placeholder="Ej: 1")
                n_dpto  = st.text_input("N° Dpto", placeholder="Ej: 101")
                n_dni   = st.text_input("DNI (8 dígitos)", placeholder="Ej: 08165632", max_chars=8)
            with fa2:
                n_nombre = st.text_input("Nombres y Apellidos")
                n_cel    = st.text_input("Celular")
                n_sit    = st.selectbox("Situación", ["","PROPIETARIO","ALQUILER","DESOCUPADO"])
            with fa3:
                n_dir    = st.text_input("Dirección")
                n_correo = st.text_input("Correo")

            col_g, col_c = st.columns(2)
            with col_g: guardar = st.form_submit_button("💾 GUARDAR", use_container_width=True)
            with col_c: cancelar= st.form_submit_button("✖ CANCELAR", use_container_width=True)

            if guardar:
                # Validar DNI 8 dígitos
                dni_val = n_dni.strip().zfill(8) if n_dni.strip() else ""
                if n_dni and len(n_dni.strip()) != 8:
                    st.error("⚠️ El DNI debe tener exactamente 8 dígitos")
                elif not n_nombre:
                    st.error("⚠️ El nombre es obligatorio")
                else:
                    t = str(int(n_torre)).zfill(2) if n_torre else ""
                    d = str(int(n_dpto)).zfill(3) if n_dpto else ""
                    cod = t + d if t and d else ""
                    nuevo = {
                        "codigo": cod, "torre": n_torre, "dpto": n_dpto,
                        "dni": dni_val, "nombre": n_nombre.upper(),
                        "direccion": n_dir, "celular": n_cel,
                        "correo": n_correo, "situacion": n_sit
                    }
                    st.session_state.df = pd.concat(
                        [st.session_state.df, pd.DataFrame([nuevo])],
                        ignore_index=True
                    )
                    st.session_state["modo_agregar"] = False
                    st.success(f"✅ Propietario {n_nombre.upper()} agregado!")
                    st.rerun()
            if cancelar:
                st.session_state["modo_agregar"] = False
                st.rerun()

    # ── ELIMINAR ──
    if btn_eliminar:
        if hay_busqueda and len(resultado) == 1:
            p = resultado.iloc[0]
            st.warning(f"⚠️ ¿Eliminar a **{p['nombre']}** (DNI: {p['dni']})? Esta acción no se puede deshacer.")
            ce1, ce2 = st.columns(2)
            with ce1:
                if st.button("✅ SÍ, ELIMINAR", key="confirm_del"):
                    idx = resultado.index[0]
                    st.session_state.df = st.session_state.df.drop(idx).reset_index(drop=True)
                    st.success("✅ Eliminado correctamente")
                    st.rerun()
            with ce2:
                if st.button("❌ CANCELAR", key="cancel_del"):
                    st.rerun()
        else:
            st.warning("⚠️ Para eliminar, busca primero un propietario específico (resultado único)")

    # ── MOSTRAR RESULTADOS ──
    if hay_busqueda and not st.session_state.get("modo_agregar"):
        st.markdown(f"**Se encontraron {len(resultado)} resultado(s)**")
        if len(resultado) > 0:
            tabla = resultado[["codigo","dni","nombre","torre","dpto","celular","situacion"]].copy()
            tabla.columns = ["Código","DNI","Nombres y Apellidos","Torre","N° Dpto","Celular","Situación"]
            st.dataframe(tabla.reset_index(drop=True), use_container_width=True, hide_index=True)

            if len(resultado) == 1:
                p = resultado.iloc[0]
                st.markdown("---")
                st.markdown("#### 📋 Detalle")
                d1,d2,d3 = st.columns(3)
                with d1:
                    st.info(f"**Código:** {p['codigo'] or '—'}")
                    st.info(f"**DNI:** {p['dni'] or '—'}")
                    st.info(f"**Torre:** {p['torre'] or '—'} | **Dpto:** {p['dpto'] or '—'}")
                with d2:
                    st.info(f"**Nombre:** {p['nombre']}")
                    st.info(f"**Celular:** {p['celular'] or '—'}")
                    st.info(f"**Situación:** {p['situacion'] or '—'}")
                with d3:
                    st.info(f"**Correo:** {p['correo'] or '—'}")
                    st.info(f"**Dirección:** {p['direccion'] or '—'}")
        else:
            st.warning("No se encontraron resultados.")
    elif not hay_busqueda and not st.session_state.get("modo_agregar"):
        st.info("👆 Ingresa DNI, Código o Nombre para buscar")

# ══════════════════════════════════════════════════════════════════════════════
# PÁGINA: DATOS PROPIETARIOS
# ══════════════════════════════════════════════════════════════════════════════
elif pagina == "📊 Datos Propietarios":
    st.markdown("### 📊 Datos Propietarios")
    filtro = st.text_input("🔍 Filtrar (DNI, nombre, código, torre):")
    if filtro:
        mask = (
            df["dni"].str.contains(filtro, case=False, na=False) |
            df["nombre"].str.contains(filtro, case=False, na=False) |
            df["codigo"].str.contains(filtro, case=False, na=False) |
            df["torre"].str.contains(filtro, case=False, na=False)
        )
        mostrar = df[mask]
    else:
        mostrar = df
    st.markdown(f"Mostrando **{len(mostrar)}** propietarios")
    tabla = mostrar[["codigo","torre","dpto","dni","nombre","celular","correo","situacion"]].copy()
    tabla.columns = ["Código","Torre","N° Dpto","DNI","Nombres y Apellidos","Celular","Correo","Situación"]
    st.dataframe(tabla.reset_index(drop=True), use_container_width=True, hide_index=True, height=500)
    csv = tabla.to_csv(index=False).encode("utf-8")
    st.download_button("⬇️ Descargar CSV", csv, "propietarios.csv", "text/csv")

# ══════════════════════════════════════════════════════════════════════════════
# PÁGINA: OPERACIONES
# ══════════════════════════════════════════════════════════════════════════════
elif pagina == "💰 Operaciones":
    st.markdown("### 💰 Operaciones")
    st.info("🚧 Módulo en desarrollo — próximamente disponible")

# ══════════════════════════════════════════════════════════════════════════════
# PÁGINA: DASHBOARD
# ══════════════════════════════════════════════════════════════════════════════
elif pagina == "📈 Dashboard":
    st.markdown("### 📈 Dashboard")
    c1,c2,c3,c4 = st.columns(4)
    c1.metric("Total Propietarios", len(df))
    c2.metric("Torres", 19)
    c3.metric("Con correo", df[df["correo"].str.strip()!=""].shape[0])
    c4.metric("Con celular", df[df["celular"].str.strip()!=""].shape[0])
    st.markdown("---")
    st.markdown("#### Propietarios por Torre")
    por_torre = df[df["torre"].str.strip()!=""].groupby("torre").size().reset_index(name="cantidad")
    por_torre["torre"] = por_torre["torre"].apply(lambda x: f"Torre {x}")
    st.bar_chart(por_torre.set_index("torre"))
